-- grid_rows
DROP TABLE IF EXISTS `grid_rows`;
CREATE TABLE grid_rows (
    uuid VARCHAR(96) NOT NULL,
    provider VARCHAR(32) NOT NULL,
    kind VARCHAR(32) NOT NULL,
    source_label VARCHAR(32) NOT NULL,
    when_ts VARCHAR(40) NOT NULL,
    author VARCHAR(255),
    account VARCHAR(96),
    project VARCHAR(96),
    channel VARCHAR(255),
    conversation_name VARCHAR(512),
    conversation_uuid VARCHAR(96) NOT NULL,
    message_index INT,
    entire_chat VARCHAR(255) NOT NULL,
    text LONGTEXT NOT NULL,
    slack_link VARCHAR(512),
    qmd_path VARCHAR(512),
    source_url VARCHAR(1024),
    git_sha VARCHAR(64),
    external_id VARCHAR(128),
    notion_page_uuid VARCHAR(96),
    notion_block_uuid VARCHAR(96),
    document_uuid VARCHAR(96),
    PRIMARY KEY (uuid)
);

