INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`, `qmd_path`, `source_url`, `git_sha`, `external_id`, `notion_page_uuid`, `notion_block_uuid`, `document_uuid`) VALUES ('20000002-1701-4d00-8000-000000020002', 'anthropic', 'LLM Response', 'Claude', '2369-04-13T14:05:11.000000+00:00', 'assistant', '00000002-1701-4d00-8000-000000000002', NULL, NULL, 'Warp Plasma Conduit Resonance', 'c0000002-1701-4d00-8000-00000000c002', 1, '/chat/c0000002-1701-4d00-8000-00000000c002', 'The 0.4Hz is a beat frequency between the EPS regulator (750.0Hz) and the dilithium chamber harmonic (750.4Hz). Re-tune the regulator to 750.2Hz to null it out.', NULL, 'anthropic/00000002-1701-4d00-8000-000000000002/llm_chats/c0000002-1701-4d00-8000-00000000c002__warp-plasma-conduit-resonance.qmd', NULL, NULL, NULL, NULL, NULL, 'c0000002-1701-4d00-8000-00000000c002');
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`, `qmd_path`, `source_url`, `git_sha`, `external_id`, `notion_page_uuid`, `notion_block_uuid`, `document_uuid`) VALUES ('30000001-1701-4d00-8000-000000030001', 'anthropic', 'User Input', 'Claude', '2369-04-14T10:00:00.000000+00:00', '00000001-1701-4d00-8000-000000000001', '00000001-1701-4d00-8000-000000000001', NULL, NULL, 'Klingon Diplomatic Greeting Drafting', 'c0000003-1701-4d00-8000-00000000c003', 0, '/chat/c0000003-1701-4d00-8000-00000000c003', 'Look up the Klingon greeting "nuqneH" and propose a respectful opening line for a diplomatic dispatch to Chancellor K''mpec.', NULL, 'anthropic/00000001-1701-4d00-8000-000000000001/llm_chats/c0000003-1701-4d00-8000-00000000c003__klingon-diplomatic-greeting-drafting.qmd', NULL, NULL, NULL, NULL, NULL, 'c0000003-1701-4d00-8000-00000000c003');
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`, `qmd_path`, `source_url`, `git_sha`, `external_id`, `notion_page_uuid`, `notion_block_uuid`, `document_uuid`) VALUES ('30000002-1701-4d00-8000-000000030002', 'anthropic', 'LLM Response', 'Claude', '2369-04-14T10:01:00.000000+00:00', 'claude-opus-4-7', '00000001-1701-4d00-8000-000000000001', NULL, NULL, 'Klingon Diplomatic Greeting Drafting', 'c0000003-1701-4d00-8000-00000000c003', 1, '/chat/c0000003-1701-4d00-8000-00000000c003', 'For a dispatch to Chancellor K''mpec, open with "qaleghneS, Chancellor — nuqneH?" ("I am honored to see you — what do you want?"). The honorific softens the bluntness of nuqneH; together they read as warm-but-direct, which Klingons respect.', NULL, 'anthropic/00000001-1701-4d00-8000-000000000001/llm_chats/c0000003-1701-4d00-8000-00000000c003__klingon-diplomatic-greeting-drafting.qmd', NULL, NULL, NULL, NULL, NULL, 'c0000003-1701-4d00-8000-00000000c003');
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`, `qmd_path`, `source_url`, `git_sha`, `external_id`, `notion_page_uuid`, `notion_block_uuid`, `document_uuid`) VALUES ('30000002-1701-4d00-8000-000000030002:0', 'anthropic', 'LLM Thinking', 'Claude', '2369-04-14T10:00:30.000000+00:00', 'claude-opus-4-7', '00000001-1701-4d00-8000-000000000001', NULL, NULL, 'Klingon Diplomatic Greeting Drafting', 'c0000003-1701-4d00-8000-00000000c003', 1, '/chat/c0000003-1701-4d00-8000-00000000c003', '"nuqneH" literally means "what do you want" — it''s blunt by Federation standards but standard among Klingons. I should fetch a phrasebook to confirm register before recommending an opening.', NULL, 'anthropic/00000001-1701-4d00-8000-000000000001/llm_chats/c0000003-1701-4d00-8000-00000000c003__klingon-diplomatic-greeting-drafting.qmd', NULL, NULL, NULL, NULL, NULL, 'c0000003-1701-4d00-8000-00000000c003');
