INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`, `qmd_path`, `source_url`, `git_sha`, `external_id`, `notion_page_uuid`, `notion_block_uuid`, `document_uuid`) VALUES ('40000002-1701-4d00-8000-000000040002', 'anthropic', 'LLM Response', 'Claude', '2369-04-15T08:30:45.000000+00:00', 'claude-opus-4-7', '00000003-1701-4d00-8000-000000000003', NULL, NULL, 'Tricorder Image Diagnostic', 'c0000004-1701-4d00-8000-00000000c004', 1, '/chat/c0000004-1701-4d00-8000-00000000c004', 'The readout shows elevated isoboramine (62 ng/mL; reference 35–40) and depressed serotonin uptake. Consistent with early-stage Vulcan neuro-pressure deficit. Recommend mind-meld therapy at 24h intervals.', NULL, 'anthropic/00000003-1701-4d00-8000-000000000003/llm_chats/c0000004-1701-4d00-8000-00000000c004__tricorder-image-diagnostic.qmd', NULL, NULL, NULL, NULL, NULL, 'c0000004-1701-4d00-8000-00000000c004');
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`, `qmd_path`, `source_url`, `git_sha`, `external_id`, `notion_page_uuid`, `notion_block_uuid`, `document_uuid`) VALUES ('486e1044-4ddc-5430-9800-c717957920ca', 'github', 'GitHub Review Comment', 'GitHub', '2369-04-15T14:00:01Z', 'data-soong', 'jlpicard', 'enterprise-d/replicator-firmware', NULL, 'Add holodeck safety interlock for live phaser fire', '8365cf2d-2561-5cc5-bba0-657a8b9f35a2', 0, '/chat/8365cf2d-2561-5cc5-bba0-657a8b9f35a2', 'If `safeties_engaged` is read after `weapons_armed` is set, there is a 12-microsecond window in which a discharge could occur. I recommend reordering the checks.', NULL, 'github/enterprise-d/replicator-firmware/pr-43__add-holodeck-safety-interlock-for-live-phaser-fire/threads/src-holodeck-safety-c-L200.qmd', 'https://github.com/enterprise-d/replicator-firmware/pull/43#discussion_r4300301', '1701d00043bbbbbbbbbbbbbbbbbbbbbbbbbbbbbb', '4300301', NULL, NULL, '8365cf2d-2561-5cc5-bba0-657a8b9f35a2');
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`, `qmd_path`, `source_url`, `git_sha`, `external_id`, `notion_page_uuid`, `notion_block_uuid`, `document_uuid`) VALUES ('50000001-1701-4d00-8000-000000050001', 'anthropic', 'User Input', 'Claude', '2369-04-16T09:00:00.000000+00:00', '00000001-1701-4d00-8000-000000000001', '00000001-1701-4d00-8000-000000000001', NULL, NULL, 'Borg Encryption Signature Lookup', 'c0000005-1701-4d00-8000-00000000c005', 0, '/chat/c0000005-1701-4d00-8000-00000000c005', 'Look up the Borg adaptive-shield signature 7-of-9-alpha and tell me if we have a counter on file.', NULL, 'anthropic/00000001-1701-4d00-8000-000000000001/llm_chats/c0000005-1701-4d00-8000-00000000c005__borg-encryption-signature-lookup.qmd', NULL, NULL, NULL, NULL, NULL, 'c0000005-1701-4d00-8000-00000000c005');
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`, `qmd_path`, `source_url`, `git_sha`, `external_id`, `notion_page_uuid`, `notion_block_uuid`, `document_uuid`) VALUES ('50000002-1701-4d00-8000-000000050002', 'anthropic', 'LLM Response', 'Claude', '2369-04-16T09:01:30.000000+00:00', 'claude-opus-4-7', '00000001-1701-4d00-8000-000000000001', NULL, NULL, 'Borg Encryption Signature Lookup', 'c0000005-1701-4d00-8000-00000000c005', 1, '/chat/c0000005-1701-4d00-8000-00000000c005', 'Yes — we have a counter on file. Rotating phaser modulation at 257.4 MHz (±0.6) gives roughly two effective rounds before the Borg re-adapt. Recommend pre-loading the rotation pattern before engagement.', NULL, 'anthropic/00000001-1701-4d00-8000-000000000001/llm_chats/c0000005-1701-4d00-8000-00000000c005__borg-encryption-signature-lookup.qmd', NULL, NULL, NULL, NULL, NULL, 'c0000005-1701-4d00-8000-00000000c005');
