INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`, `qmd_path`, `source_url`, `git_sha`, `external_id`, `notion_page_uuid`, `notion_block_uuid`, `document_uuid`) VALUES ('b10cb10c-1701-4d00-8000-000000000002', 'notion', 'Notion Page', 'Notion', '2369-05-28T15:10:00.000000+00:00', 'William T. Riker', 'USS Enterprise-D Operations', NULL, NULL, 'Bridge Operations', 'b10cb10c-1701-4d00-8000-000000000002', NULL, '/notion/b10cb10c-1701-4d00-8000-000000000002', 'Bridge Operations\nBridge watch — Beta shift\nBridge watch — Alpha shift\naway-team-roster-stardate-46531.pdf\ndef red_alert():\n    shields.raise_all()\n    weapons.arm("phasers", "photon_torpedoes")\n    intercom.broadcast("All hands, battle stations.")\nReminder: holodeck safety protocols must remain ENABLED outside of authorized drills.\nThings are only impossible until they''re not. — J-L Picard\nClick to reveal Captain''s private notes\nThe Romulan signature on long-range sensors is consistent with a D''deridex-class warbird.\nInspect EPS conduits on deck 36\nVerify deflector array alignment\nRaise shields\nSound red alert\nHail the unknown vessel on all Starfleet frequencies\nPhasers locked\nShields at maximum\nCoordinate with @Geordi La Forge before any warp-core ejection — see Warp Core Maintenance, or the protocol PDF. Inline code: red_alert(). italics here. Reference date: 2369-04-15.\nStep 1: Notify Engineering\nYellow Alert Procedures\nStanding Orders\nThis page tracks bridge-watch handoffs and standing orders. Tea, Earl Grey, hot.', NULL, 'notion/uss-enterprise-d-operations__5face1d0/uss-enterprise-d-operations__b10cb10c/bridge-operations__b10cb10c/index.qmd', 'https://www.notion.so/b10cb10c17014d008000000000000002', NULL, NULL, 'b10cb10c-1701-4d00-8000-000000000002', NULL, 'b10cb10c-1701-4d00-8000-000000000002');
